#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
const int N = 2e7+5;
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
int n,m;
struct Seg{int l,r,val,dep;}t[N]; int cnt,a[N],Rt[N],Mx[N];
inline void build(int &x,int l,int r)
{
	int mid=(l+r)>>1;x=++cnt;if(l==r){t[x].val=a[l];return;}
	build(t[x].l,l,mid);build(t[x].r,mid+1,r);return;
}
inline void Fix(int cur,int &x,int loc,int val,int l,int r)
{
	t[x=++cnt]=t[cur];int mid=(l+r)>>1;
	if(l==r){t[x].val=val;t[x].dep=t[cur].dep;return;}
	if(loc<=mid)Fix(t[cur].l,t[x].l,loc,val,l,mid);
	else Fix(t[cur].r,t[x].r,loc,val,mid+1,r);
}
inline void add(int cur,int loc,int l,int r)
{
	if(l==r){t[cur].dep++;return;} int mid=(l+r)>>1;
	if(loc<=mid){add(t[cur].l,loc,l,mid);return;}
	add(t[cur].r,loc,mid+1,r);return;
}
inline int Query(int cur,int loc,int l,int r)
{
	int mid=(l+r)>>1;if(l==r)return cur;
	if(loc<=mid)return Query(t[cur].l,loc,l,mid);
	return Query(t[cur].r,loc,mid+1,r);
}

inline int find(int a,int rt)
{
	int nf=Query(rt,a,1,n);
	return (t[nf].val==a)?nf:find(t[nf].val,rt);
}
inline void link(int a,int b,int i)
{
	Rt[i]=Rt[i-1];int Ra=find(a,Rt[i]),Rb=find(b,Rt[i]);
	if(Ra!=Rb)
	{
		if(t[Ra].dep>t[Rb].dep)swap(Ra,Rb);
		Fix(Rt[i-1],Rt[i],t[Ra].val,t[Rb].val,1,n);
		if(t[Ra].dep==t[Rb].dep)add(Rt[i],Rb,1,n);
	}
}
int main()
{
	n=read(),m=read();rep(1,n,i)a[i]=i;build(Rt[0],1,n);
	rep(1,m,i){int opt=read(),k=read();switch(opt)
	{
		case 1:	link(k,read(),i);break;
		case 2: Rt[i]=Rt[k];  break;
		case 3: Rt[i]=Rt[i-1];printf("%d\n",t[find(k,Rt[i])].val==t[find(read(),Rt[i])].val);break;
		
	}Mx[i]=cnt;}//rep(1,cnt,i)printf("%d : %d %d %d\n",i,t[i].l,t[i].r,t[i].val);
}
